mapper.select:
select

from t_behavior_record br
left join t_elder e on br.elder_id = e.id


        and br.elder_id = #{elderId}


        and e.name like concat('%', #{elderName}, '%')


        and br.behavior_type = #{behaviorType}


        and br.risk_level = #{riskLevel}


order by br.start_time desc, br.id desc

select count(1)
from t_behavior_record
where elder_id = #{elderId}
  and behavior_type = #{behaviorType}
  and behavior_name = #{behaviorName}
  and start_time = #{startTime}

    and id != #{id}
